CREATE VIEW `ads_user_appstartlog_view` (`dt` COMMENT "createtime 分区", `Productid` COMMENT "产品id", `AutoId` COMMENT "自增id", `UserId` COMMENT "用户id", `CreateTime` COMMENT "用户登录时间", `IP` COMMENT "用户ip地址", `MT` COMMENT "终端", `IMEI` COMMENT "用户手机设备识别码", `IMSI` COMMENT "国际移动用户识别码", `MAC` COMMENT "硬件地址", `Ver` COMMENT "版本号", `Chl` COMMENT "投放渠道值", `Device` COMMENT "设备号", `SW` COMMENT "客户端分辨率", `SH` COMMENT "客户端分辨率", `DeviceGUID` COMMENT "设备guid", `AppId` COMMENT "产品appid", `etl_time` COMMENT "处理时间")
